scwin.onpageload = function () {
  const codeOptions = [{
    grpCd: "ZZ006",
    compID: "lc_crcCd"
  }];
  $c.data.setCommonCode($p, codeOptions, scwin.setInit);
  $c.gus.cfDisableObjects($p, [ed_closeYm, txt_closeYn, ed_magamDt, btn_includeSave]);
  let memJson = $c.data.getMemInfo($p);
  console.log("### onpageload :: " + JSON.stringify(memJson));
  scwin.g_sUserId = memJson.empNo;
  scwin.f_retrieveAuth();
};

