scwin.setInit = function () {
  lc_crcCd.addItem("전체", "", null, 0);
  lc_crcCd.setValue("USD");
  ds_comCode.setJSON(dlt_commonCodeZZ006.getAllJSON());
};
scwin.f_retrieveAuth = function () {
  sbm_auth.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=retrieveBorrowAcqKindInfo&param1=IL110" + "&param2=" + scwin.g_sUserId;
  $c.sbm.execute($p, sbm_auth);
};
scwin.f_getMagam = function () {
  var vStdYm = ed_stdYm.getValue();

  // SELECT 절 
  var param1 = " TO_CHAR(MAX(A.REG_DTM),'YYYYMMDD')  as COL1 " + ",''      as COL2 " + ",''      as COL3 " + ",'' 		as COL4 " + ",'' 		as COL5 " + ",'' 		as COL6 " + ",''      as COL7 " + ",''      as COL8 " + ",''      as COL9 " + ",''      as COL10";

  // 대상테이블 	
  var param2 = " TB_ZZ420 A, TB_ZZ419 B";

  // 조건절
  var param3 = " AND A.CLOSE_YM = '" + vStdYm + "'" + " AND A.WRK_NO = 'IL01' " + " AND A.CLOSE_YM = B.CLOSE_YM " + " AND A.WRK_NO = B.WRK_NO " + " AND B.CLOSE_PRGS_STS_CD = '2' ";
  sbm_magam.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=A.REG_DTM";
  $c.sbm.execute($p, sbm_magam);
};
scwin.getLastDayOfMonth = function () {
  yyyymm = ed_stdYm.getValue();
  if (!yyyymm || yyyymm.length !== 6) return "";
  var year = parseInt(yyyymm.substring(0, 4), 10);
  var month = parseInt(yyyymm.substring(4, 6), 10);

  // 다음 달 0일 = 현재 달 마지막 날
  var lastDt = new Date(year, month, 0).getDate();
  if (lastDt == '31') {
    gr_acctRecvList.setColumnVisible("amt29d", "true");
    gr_acctRecvList.setColumnVisible("amt30d", "true");
    gr_acctRecvList.setColumnVisible("amt31d", "true");
  } else if (lastDt == '30') {
    gr_acctRecvList.setColumnVisible("amt29d", "true");
    gr_acctRecvList.setColumnVisible("amt30d", "true");
    gr_acctRecvList.setColumnVisible("amt31d", "false");
  } else if (lastDt == '29') {
    gr_acctRecvList.setColumnVisible("amt29d", "true");
    gr_acctRecvList.setColumnVisible("amt30d", "false");
    gr_acctRecvList.setColumnVisible("amt31d", "false");
  } else if (lastDt == '28') {
    gr_acctRecvList.setColumnVisible("amt29d", "false");
    gr_acctRecvList.setColumnVisible("amt30d", "false");
    gr_acctRecvList.setColumnVisible("amt31d", "false");
  }
};
scwin.f_Retrieve = function () {
  if (ed_stdYm.getValue() == "") {
    $c.win.alert($p, "기준년월은(는) 필수 입력 항목 입니다.");
    return;
  }
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.f_add = function () {
  idx = ds_additionalValue.insertRow();
  ds_additionalValue.setCellData(idx, "crcCd", "USD");
  ds_additionalValue.setCellData(idx, "additionalKndCd", "1");
  ds_additionalValue.setCellData(idx, "amtFcrc", "0");
  gr_additionalValue.setFocusedCell(idx, 0);
  gr_additionalValue.setReadOnly("cell", idx, 0, false);
  gr_additionalValue.setReadOnly("cell", idx, 2, false);
  gr_additionalValue.setReadOnly("cell", idx, 4, false);
  gr_additionalValue.setReadOnly("cell", idx, 5, false);
};
scwin.f_delete = function () {
  row = gr_additionalValue.getFocusedRowIndex();
  if (ds_additionalValue.getRowStatus(row) == "C") {
    ds_additionalValue.removeRow(row);
    return;
  }
  if (ds_auth.getTotalRow() != 0 || ds_additionalValue.getCellData(gr_additionalValue.getFocusedRowIndex(), "regId") == scwin.g_sUserId || "" == ds_additionalValue.getCellData(gr_additionalValue.getFocusedRowIndex(), "regId")) {
    ds_additionalValue.modifyRowStatus(gr_additionalValue.getFocusedRowIndex(), "D");
  } else {
    $c.win.alert($p, "작성자만 삭제할 수 있습니다.");
  }
};
scwin.f_cancel = function () {
  row = gr_additionalValue.getFocusedRowIndex();
  if (ds_additionalValue.getRowStatus(row) == "C") {
    ds_additionalValue.removeRow(row);
    return;
  }
  if (ds_additionalValue.getRowStatus() == "C") {
    ds_additionalValue.removeRow();
  } else {
    ds_additionalValue.undoRow(gr_additionalValue.getFocusedRowIndex());
  }
};
scwin.f_openPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
  // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
  // 넘어온 OBJ가 EMEdit인지 TextBox인지 구분한다.
  if (flag == "ALL") {
    cd = "";
    nm = "";
  } else {
    cd = orgObjCd.getValue();
    nm = orgObjNm.getValue();
  }
  switch (select_code) {
    // 조회조건용 거래처 PopUp 호출
    case '1':
      break;
    case '2':
      param = "000";
      udc_clnt.setSelectId("retrieveClntEmpNoList");
      udc_clnt.cfCommonPopUp(scwin.udc_clnt_callbackFunc, cd, nm, "T", null, null, null, null, null, null, null, null, null); //사업자번호
      break;
    case '31':
      udc_user.setSelectId("retrieveAcEmpInfo");
      udc_user.cfCommonPopUp(scwin.udc_user_callbackFunc, cd, nm, "T", null, null, null, null, null, null, null, null, null); // 거래처
      break;
    case '32':
      udc_pic.setSelectId("retrieveAcEmpInfo");
      udc_pic.cfCommonPopUp(scwin.udc_pic_callbackFunc, cd, nm, "T", null, null, null, null, null, null, null, null, null); // 거래처
      break;
    case '33':
      udc_reg.setSelectId("retrieveAcEmpInfo");
      udc_reg.cfCommonPopUp(scwin.udc_reg_callbackFUnc, cd, nm, "T", null, null, null, null, null, null, null, null, null); // 거래처
      break;
  }
};
